-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الثقافة الإسلامية والفكر" (thaqafa-fikr) — تستنفد العنقود بالكامل
-- (7 تصنيفات فرعية من أصل 7، كلها بلا محتوى): الهوية الإسلامية، الوسطية
-- والغلو، التيارات الفكرية المعاصرة، الاستشراق، العولمة والإعلام،
-- الشبهات المعاصرة، التفكير النقدي والتحقق من المعلومات.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: شخصية المسلم كما
-- يصوغها الإسلام لمحمد علي الهاشمي، الغلو في الدين في حياة المسلمين
-- المعاصرة لعبدالرحمن بن معلا اللويحق، مذاهب فكرية معاصرة لمحمد قطب،
-- الاستشراق والمستشرقون لمصطفى السباعي، المسلمون والعولمة ليوسف
-- القرضاوي، شبهات حول الإسلام لمحمد قطب، التفكير فريضة إسلامية لعباس
-- محمود العقاد.
-- الآيات المستشهَد بها (الحجرات:13، البقرة:143، البقرة:170، آل
-- عمران:118، الحجرات:6، الإسراء:81، الإسراء:36) تحقَّقت حرفياً من
-- artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah قبل
-- الإدراج.
-- حديث واحد فقط استُشهد به بعد تحقُّق عبر WebSearch: «هلك المتنطعون»
-- (صحيح مسلم رقم 2670، عن عبدالله بن مسعود رضي الله عنه). حديث آخر
-- («بئس مطية الرجل زعموا») بُحث عنه لتصنيف التفكير النقدي ولم يُدرَج
-- لاختلاف العلماء في وصله وإرساله (انقطاع في الإسناد رجّحه ابن حجر رغم
-- تصحيح الألباني له)، فاكتُفي بالآية والمصدر الكتابي فقط لذلك التصنيف.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات السبعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الهوية الإسلامية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='663951c6-c456-46d6-be34-8ee87fea6575' AND title='الهوية الإسلامية: مفهومها ومقوماتها في مواجهة الذوبان') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الهوية الإسلامية: مفهومها ومقوماتها في مواجهة الذوبان', 'تعريف موجز بمفهوم الهوية الإسلامية وأبرز مقوماتها التي تحفظ للمسلم تميزه في محيط متعدد الثقافات', '663951c6-c456-46d6-be34-8ee87fea6575', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الهوية الإسلامية', 'الهوية الإسلامية هي مجموع الخصائص العقدية والفكرية والسلوكية التي تميز شخصية الفرد المسلم والأمة المسلمة عن غيرها، وأساسها الانتماء العقدي لدين الإسلام قبل أي انتماء عرقي أو قومي أو وطني، بحيث تصبح العقيدة هي الرابطة الجامعة بين المسلمين على اختلاف ألسنتهم وأجناسهم وأوطانهم.', 1),
    (v_lesson, 'terms', 'مقومات الهوية الإسلامية', 'من أبرز مقومات الهوية الإسلامية: العقيدة الصحيحة الجامعة، والانتماء إلى تاريخ الأمة وتراثها العلمي والحضاري، والتمسك باللغة العربية بوصفها وعاء القرآن الكريم، والالتزام بالأخلاق والآداب الإسلامية في التعامل والسلوك. وحفظ هذه المقومات لا يعني الانغلاق عن الآخر، بل التعارف معه من موقع الثقة بالذات لا الذوبان فيه.', 2),
    (v_lesson, 'evidence', 'التعارف مع الحفاظ على الهوية', 'قال تعالى: ﴿يَا أَيُّهَا النَّاسُ إِنَّا خَلَقْنَاكُم مِّن ذَكَرٍ وَأُنثَىٰ وَجَعَلْنَاكُمْ شُعُوبًا وَقَبَائِلَ لِتَعَارَفُوا ۚ إِنَّ أَكْرَمَكُمْ عِندَ اللَّهِ أَتْقَاكُمْ﴾ (الحجرات: 13)، فالآية تقرر أن التمايز بين الشعوب والقبائل غاية التعارف لا الذوبان، وأن معيار التفاضل الحقيقي هو التقوى لا اللون أو العرق أو القومية.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'شخصية المسلم كما يصوغها الإسلام في الكتاب والسنة — محمد علي الهاشمي', 1);
  END IF;

  -- 2) الوسطية والغلو
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a3209d4d-1c2b-4c32-9434-249f055a9741' AND title='الوسطية في الإسلام وذم الغلو والتنطع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الوسطية في الإسلام وذم الغلو والتنطع', 'تعريف موجز بمفهوم الوسطية بوصفها سمة عامة للأمة الإسلامية، وذم الغلو والتشدد الذي يجاوز حدود الشرع', 'a3209d4d-1c2b-4c32-9434-249f055a9741', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'مفهوم الوسطية', 'الوسطية في الشرع هي التوسط بين طرفي الإفراط والتفريط في الاعتقاد والعبادة والسلوك، فلا غلوٌّ يجاوز حدود الشرع بتشديد ما لم يشدده الله، ولا تفريطٌ يقصر عن أداء الواجبات، وهي سمة عامة وصف الله بها هذه الأمة دون غيرها من الأمم.', 1),
    (v_lesson, 'terms', 'مظاهر الغلو وذمّه', 'الغلو هو مجاوزة الحد في الدين بالتشديد على النفس أو على الغير فيما لم يرد الشرع بالتشديد فيه، ومن مظاهره: التنطع في الأحكام الفرعية، وتكفير المخالف بغير دليل شرعي معتبر، والتشدد الذي يورث الملل أو النفور من الدين. وقد حذر النبي صلى الله عليه وسلم أمته من هذا المسلك أشد التحذير.', 2),
    (v_lesson, 'evidence', 'وصف الأمة بالوسطية', 'قال تعالى: ﴿وَكَذَٰلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِّتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا﴾ (البقرة: 143)', 3),
    (v_lesson, 'evidence', 'ذم التنطع في الحديث', 'عن عبدالله بن مسعود رضي الله عنه أن النبي صلى الله عليه وسلم قال: «هَلَكَ الْمُتَنَطِّعُونَ» قالها ثلاث مرات، رواه مسلم.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الغلو في الدين في حياة المسلمين المعاصرة — عبدالرحمن بن معلا اللويحق', 1),
    (v_lesson, 'book', 'صحيح مسلم، كتاب العلم، رقم 2670', 2);
  END IF;

  -- 3) التيارات الفكرية المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='81b50708-937b-4b5c-b52f-483439a3f132' AND title='التيارات الفكرية المعاصرة: تعريفها وموقف المسلم منها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التيارات الفكرية المعاصرة: تعريفها وموقف المسلم منها', 'تعريف موجز بأبرز التيارات الفكرية الوافدة التي تواجه الفكر الإسلامي المعاصر، وضوابط التعامل معها', '81b50708-937b-4b5c-b52f-483439a3f132', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف التيار الفكري', 'التيار الفكري هو مجموعة من الأفكار والمفاهيم المتماسكة التي تنتشر بين فئة من الناس وتشكل رؤية معينة للكون والإنسان والحياة، وقد ووجه الفكر الإسلامي المعاصر بتيارات وافدة من خارج منظومته العقدية كالعلمانية (فصل الدين عن شؤون الحياة والدولة) والمادية (إنكار ما وراء المحسوس)، إلى جانب تيارات نشأت من داخل الساحة الإسلامية كرد فعل، كبعض تيارات الغلو والتطرف.', 1),
    (v_lesson, 'terms', 'ضوابط التعامل مع التيارات الوافدة', 'يقوم المنهج الإسلامي في التعامل مع التيارات الفكرية الوافدة على أصلين: الفهم الدقيق لمضمون التيار قبل الحكم عليه، ثم عرضه على ميزان الكتاب والسنة، فما وافق أصول الشريعة من منهج أو أداة بحث يُستفاد منه، وما خالف عقيدة التوحيد أو أحكام الشريعة القطعية يُرد، دون تعميم بالرفض أو القبول الأعمى لكل وافد.', 2),
    (v_lesson, 'evidence', 'ذم اتباع الآباء بغير دليل', 'قال تعالى: ﴿وَإِذَا قِيلَ لَهُمُ اتَّبِعُوا مَا أَنزَلَ اللَّهُ قَالُوا بَلْ نَتَّبِعُ مَا أَلْفَيْنَا عَلَيْهِ آبَاءَنَا ۗ أَوَلَوْ كَانَ آبَاؤُهُمْ لَا يَعْقِلُونَ شَيْئًا وَلَا يَهْتَدُونَ﴾ (البقرة: 170)، والآية أصل في ذم التقليد الأعمى لأي فكر أو منهج موروث أو وافد دون إعمال العقل وعرضه على الحق.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مذاهب فكرية معاصرة — محمد قطب', 1);
  END IF;

  -- 4) الاستشراق
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='70604ac6-e9d7-486b-b872-a9f860b6109b' AND title='الاستشراق: نشأته وأبرز اتجاهاته') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الاستشراق: نشأته وأبرز اتجاهاته', 'تعريف موجز بعلم الاستشراق ونشأته التاريخية وأبرز اتجاهات المستشرقين تجاه الإسلام', '70604ac6-e9d7-486b-b872-a9f860b6109b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الاستشراق ونشأته', 'الاستشراق هو مجموع الدراسات التي قام بها غربيون (مستشرقون) حول الشرق عمومًا والإسلام والمسلمين خصوصًا، من لغة وتاريخ وعقيدة وشريعة. نشأ الاستشراق في أحضان الكنيسة الأوروبية في القرون الوسطى بدافع ديني (الرد على الإسلام)، ثم تطور مع الاستعمار الأوروبي للبلاد الإسلامية ليخدم أغراضًا سياسية واقتصادية إلى جانب الدافع الديني.', 1),
    (v_lesson, 'terms', 'اتجاهات المستشرقين', 'تفاوتت اتجاهات المستشرقين تفاوتًا كبيرًا؛ فمنهم من عادى الإسلام عداءً ظاهرًا وشكك في مصادره ونسب إليه ما ليس فيه، ومنهم من أنصف في بعض المسائل التاريخية أو اللغوية مع بقاء منهجه العلماني في التعامل مع النص الديني، ومنهم من أسلم بعد بحثه ودراسته. وقد تصدى علماء الأمة لدراسات المستشرقين بالنقد العلمي المنهجي دون رفض كل ما جاؤوا به جملة.', 2),
    (v_lesson, 'evidence', 'التحذير من موالاة من يكيد للأمة', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَتَّخِذُوا بِطَانَةً مِّن دُونِكُمْ لَا يَأْلُونَكُمْ خَبَالًا وَدُّوا مَا عَنِتُّمْ قَدْ بَدَتِ الْبَغْضَاءُ مِنْ أَفْوَاهِهِمْ وَمَا تُخْفِي صُدُورُهُمْ أَكْبَرُ ۚ قَدْ بَيَّنَّا لَكُمُ الْآيَاتِ ۖ إِن كُنتُمْ تَعْقِلُونَ﴾ (آل عمران: 118)', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الاستشراق والمستشرقون: ما لهم وما عليهم — مصطفى السباعي', 1);
  END IF;

  -- 5) العولمة والإعلام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='74031605-5f77-4fbf-95bc-070ccf26476d' AND title='العولمة والإعلام: الأثر والموقف الشرعي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('العولمة والإعلام: الأثر والموقف الشرعي', 'تعريف موجز بمفهوم العولمة وأثر وسائل الإعلام المعاصرة في نشرها، والضوابط الشرعية للتعامل معها', '74031605-5f77-4fbf-95bc-070ccf26476d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف العولمة', 'العولمة مصطلح يشير إلى تحول العالم إلى ما يشبه القرية الواحدة، بفعل الثورة الهائلة في وسائل الاتصال والإعلام والتقنية، بحيث تنتشر الأفكار والسلع والأنماط الثقافية عبر الحدود بسرعة فائقة دون قيود تُذكر، ويكون لوسائل الإعلام الدور الأكبر في تشكيل هذا الانتشار وتوجيهه.', 1),
    (v_lesson, 'terms', 'موقف المسلم من العولمة الإعلامية', 'العولمة ظاهرة ذات وجهين: وجه نافع يتمثل في تيسير التواصل ونقل العلم النافع وتبليغ الدعوة إلى أرجاء المعمورة، ووجه ضار يتمثل في تسويق أنماط ثقافية وسلوكية تخالف عقيدة الأمة وأخلاقها تحت غطاء "العالمية". والموقف الشرعي السليم هو الإفادة من أدوات العصر الإعلامية في نشر الخير، مع اليقظة التامة من توظيفها في غزو فكري يذيب خصوصية الأمة.', 2),
    (v_lesson, 'evidence', 'التثبت من الأخبار قبل تصديقها ونشرها', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِن جَاءَكُمْ فَاسِقٌ بِنَبَإٍ فَتَبَيَّنُوا أَن تُصِيبُوا قَوْمًا بِجَهَالَةٍ فَتُصْبِحُوا عَلَىٰ مَا فَعَلْتُمْ نَادِمِينَ﴾ (الحجرات: 6)، وهذا التوجيه القرآني من أهم الأصول التي ينبغي أن يستحضرها المسلم في زمن تدفق الأخبار عبر وسائل الإعلام ومنصات التواصل.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المسلمون والعولمة — يوسف القرضاوي', 1);
  END IF;

  -- 6) الشبهات المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c49da00f-857c-46bf-8ec4-9e7ff031c682' AND title='الشبهات المعاصرة حول الإسلام: طبيعتها ومنهج الرد عليها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الشبهات المعاصرة حول الإسلام: طبيعتها ومنهج الرد عليها', 'تعريف موجز بمفهوم الشبهة الفكرية وأسباب انتشارها في العصر الحاضر، ومنهج علمي للرد عليها', 'c49da00f-857c-46bf-8ec4-9e7ff031c682', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الشبهة', 'الشبهة هي إيراد يُلقى على أصل من أصول الدين أو حكم من أحكامه بصورة توهم بطلانه أو تناقضه، وهي في حقيقتها لا تقوى على الثبات أمام النظر العلمي الدقيق، لكنها تؤثر في من ضعف تحصيله العلمي أو تسرّع في تصديق ما يعرض عليه دون تمحيص. ومن أسباب انتشارها في العصر الحاضر سهولة تداول المعلومة عبر الإعلام الرقمي دون رقيب علمي.', 1),
    (v_lesson, 'terms', 'منهج الرد على الشبهات', 'يقوم الرد العلمي على الشبهة على ثلاث خطوات: فهم الشبهة فهمًا دقيقًا كما أرادها صاحبها دون تهويل أو تهوين، ثم الرجوع إلى كلام أهل العلم المتخصصين في الرد عليها بدل الاجتهاد الشخصي المتسرع، ثم بيان وجه الخطأ فيها بدليل علمي واضح مع تقديم الحق الذي يقابلها بأسلوب مقنع هادئ.', 2),
    (v_lesson, 'evidence', 'زهوق الباطل أمام الحق', 'قال تعالى: ﴿وَقُلْ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ ۚ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا﴾ (الإسراء: 81)، وفي هذا تثبيت لمن يتصدى للشبهات بأن الحق ثابت بذاته وأن الباطل زائل مهما طال جدله.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'شبهات حول الإسلام — محمد قطب', 1);
  END IF;

  -- 7) التفكير النقدي والتحقق من المعلومات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='29a6e197-664c-44c1-9556-e6f71fcc650c' AND title='التفكير النقدي والتحقق من المعلومات في ضوء الإسلام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التفكير النقدي والتحقق من المعلومات في ضوء الإسلام', 'تعريف موجز بمفهوم التفكير النقدي وأصل التثبت من الأخبار في الإسلام قبل تصديقها أو نقلها', '29a6e197-664c-44c1-9556-e6f71fcc650c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف التفكير النقدي', 'التفكير النقدي هو القدرة على تحليل المعلومة أو الادعاء وتقييم أدلته ومصادره قبل قبوله أو رفضه، بدلًا من التسليم الفوري لكل ما يُعرض من أخبار أو آراء. وقد دعا الإسلام إلى إعمال العقل والتفكر والتدبر، ونهى عن اتباع الظن أو القول بغير علم.', 1),
    (v_lesson, 'terms', 'أصل التثبت في المصدر الشرعي', 'من أهم قواعد التحقق من المعلومة في الإسلام: عدم القول أو النقل بغير علم موثق، والتحري عن مصدر الخبر وصحته قبل تصديقه أو نشره، والتمييز بين ما هو مبني على نص أو دليل صحيح وما هو مجرد ظن أو شائعة متداولة، وهذا هو جوهر ما يُعرف اليوم بـ"التحقق من المعلومات".', 2),
    (v_lesson, 'evidence', 'النهي عن اتباع ما لا علم به', 'قال تعالى: ﴿وَلَا تَقْفُ مَا لَيْسَ لَكَ بِهِ عِلْمٌ ۚ إِنَّ السَّمْعَ وَالْبَصَرَ وَالْفُؤَادَ كُلُّ أُولَٰئِكَ كَانَ عَنْهُ مَسْئُولًا﴾ (الإسراء: 36)، فالآية تقرر مسؤولية الإنسان عن كل ما يسمعه ويبصره وما يقتنع به قلبه، فلا يجوز أن يبني حكمًا أو نقلًا على غير علم متحقق.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'التفكير فريضة إسلامية — عباس محمود العقاد', 1);
  END IF;

